const body = $json.body ?? $json;

const amount = Number(body.amount || 0).toLocaleString('pt-BR', {
  style: 'currency',
  currency: body.currency_id || 'BRL',
});

const parts = [
  '💰 Saque de afiliado solicitado',
  '',
  `Afiliado: ${body.affiliate_code || 'desconhecido'}`,
  `Valor: ${amount}`,
  `Chave PIX: ${body.pix_key || 'não informada'}`,
  `ID do saque: ${body.payout_id || '-'}`,
];

if (body.action_paid_url) {
  parts.push('', '✅ Após fazer o PIX, marcar como PAGO:', body.action_paid_url);
}

if (body.action_rejected_url) {
  parts.push('', '❌ Rejeitar (devolve o saldo):', body.action_rejected_url);
}

if (!body.action_paid_url && !body.action_rejected_url) {
  parts.push('', 'Dê baixa pelo painel n8n ou pela função settle_affiliate_payout.');
}

return [{ json: { message: parts.join('\n') } }];
